import pandas as pd

# Function to count high volatility days
def count_volatility_days(data_file):
    if isinstance(data_file, str):
        with open(data_file, 'r') as f:
            data = json.load(f)
    else:
        data = data_file

    if not data or len(data) == 0:
        return 0

    df = pd.DataFrame(data)
    df['High'] = pd.to_numeric(df['High'])
    df['Low'] = pd.to_numeric(df['Low'])

    return int(((df['High'] - df['Low']) > (df['Low'] * 0.20)).sum())

# Load company info
ticker_file = locals()['var_functions.query_db:34']
if isinstance(ticker_file, str):
    with open(ticker_file, 'r') as f:
        capital_market_tickers = json.load(f)
else:
    capital_market_tickers = ticker_file

symbol_to_company = {t['Symbol']: t['Company Description'] for t in capital_market_tickers}

# Add newly queried tickers to our results
new_data_files = {
    'BHAT': locals()['var_functions.query_db:92'],
    'CBAT': locals()['var_functions.query_db:93'],
    'DZSI': locals()['var_functions.query_db:94'],
    'FTFT': locals()['var_functions.query_db:95'],
    'OPTT': locals()['var_functions.query_db:96']
}

# Get existing results
existing_results = [
    {'symbol': 'BIOC', 'days': 21, 'company': symbol_to_company['BIOC']},
    {'symbol': 'IDEX', 'days': 15, 'company': symbol_to_company['IDEX']},
    {'symbol': 'NXTD', 'days': 15, 'company': symbol_to_company['NXTD']},
    {'symbol': 'VVPR', 'days': 14, 'company': symbol_to_company['VVPR']},
    {'symbol': 'AGMH', 'days': 13, 'company': symbol_to_company['AGMH']},
    {'symbol': 'XBIOW', 'days': 7, 'company': symbol_to_company['XBIOW']},
    {'symbol': 'BWEN', 'days': 5, 'company': symbol_to_company['BWEN']},
    {'symbol': 'HRTX', 'days': 1, 'company': symbol_to_company['HRTX']}
]

# Process new tickers
all_results = existing_results.copy()
for symbol, data_file in new_data_files.items():
    days = count_volatility_days(data_file)
    if days > 0:
        all_results.append({
            'symbol': symbol,
            'days': days,
            'company': symbol_to_company.get(symbol, 'N/A')
        })

# Sort all results
top_results = sorted(all_results, key=lambda x: x['days'], reverse=True)

print('__RESULT__:')
print(json.dumps(top_results[:10], indent=2))"}
